import { forwardRef, useContext, useEffect, useRef } from 'react';
import { useIntl } from 'react-intl';

import { ContainerIcon, ExternalLinkIcon } from '@dynatrace/strato-icons';

import { Button } from '../../../buttons/button/Button.js';
import { SEGMENTS_DOCUMENTATION_URL } from '../../../core/external-links.js';
import { Flex } from '../../../layouts/flex/Flex.js';
import { Heading } from '../../../typography/heading/Heading.js';
import { segmentsClient } from '../contexts/SegmentsCache/SegmentsCache.js';
import { UISegmentsContext } from '../contexts/SegmentsUI/SegmentsUIContext.js';
import { SEGMENTSELECTOR_MESSAGES } from '../segmentMessages.js';
import { AppLinkButtonCSS } from './EmptySegments.sty.js';
import { NoAccessWithoutSelection } from './noAccessRights/NoAccessWithoutSelection.js';
import * as styles from './Overlay.sty.js';
import { getSegmentManagementHref } from './segmentManagementHref.js';

/**
 * EmptyState-component for SegmentSelector Overlay
 * @internal
 */
export const EmptySegments = forwardRef<HTMLDivElement>(
  (props, forwardedRef) => {
    const intl = useIntl();
    const buttonRef = useRef<HTMLAnchorElement>(null);
    const { readOnly } = useContext(UISegmentsContext);
    useEffect(() => {
      // Focus the button when the component is mounted. Due to the possible loading
      // state, the overlay can't handle the focus as it tries it too early.
      buttonRef.current?.focus();
    }, []);

    if (segmentsClient.hasAccessRights === false) {
      return <NoAccessWithoutSelection />;
    }

    return (
      <Flex
        flexDirection="column"
        alignItems="center"
        padding={16}
        ref={forwardedRef}
        width="100vw"
        className={styles.overlayDefaultWidth}
        style={{ maxWidth: '320px' }}
      >
        <ContainerIcon />
        <Heading level={6}>
          {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.noSegmentsConfigured)}
        </Heading>
        <Flex
          paddingTop={8}
          width="100%"
          justifyContent={readOnly ? 'center' : 'space-between'}
        >
          {!readOnly && (
            <Button
              as="a"
              ref={buttonRef}
              href={getSegmentManagementHref()}
              target="_blank"
              rel="noopener noreferrer"
              variant="emphasized"
              className={AppLinkButtonCSS}
            >
              {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.manageSegments)}
            </Button>
          )}
          <Button
            as="a"
            href={SEGMENTS_DOCUMENTATION_URL}
            target="_blank"
            rel="noopener noreferrer"
          >
            {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.docsLinkText)}
            <Button.Suffix>
              <ExternalLinkIcon />
            </Button.Suffix>
          </Button>
        </Flex>
      </Flex>
    );
  },
);
